prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeName ?nodeType WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  }
  UNION
  {
    ?model tai:originalId "2d887704e5324e6bb2126cef061e50e9" .
  }

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?node a ?nodeType ;
        bbo:name ?nodeName .

  FILTER(
    CONTAINS(LCASE(STR(?nodeName)), LCASE("get client"))
    || CONTAINS(LCASE(STR(?nodeName)), LCASE("add"))
    || CONTAINS(LCASE(STR(?nodeName)), LCASE("cost centre"))
    || CONTAINS(LCASE(STR(?nodeName)), LCASE("cost center"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?prop (COUNT(*) AS ?count) WHERE {
  {
    ?node bbo:name ?nodeName .
    FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("get client to add the relevant cost centre")))
  }
  UNION
  {
    ?node bbo:name ?nodeName .
    FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("get client to add")))
    FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("cost centre")) || CONTAINS(LCASE(STR(?nodeName)), LCASE("cost center")))
  }

  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  }
  UNION
  {
    ?model tai:originalId "2d887704e5324e6bb2126cef061e50e9" .
  }

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .
  ?node tai:belongsTo ?choreo .

  ?node ?prop ?value .
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT 
  ?flow
  ?flowSrcRef
  ?flowTgtRef
  ?messageId
  ?messageName
WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  }
  UNION
  {
    ?model tai:originalId "2d887704e5324e6bb2126cef061e50e9" .
  }

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?node a bboExt:ChoreographyTask ;
        bbo:name ?nodeName ;
        tai:belongsTo ?choreo .
  FILTER(
    LCASE(STR(?nodeName)) = LCASE("Get client to add the relevant cost centre")
  )

  ?flow a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:sourceRef ?flowSrcRef ;
        bboExt:targetRef ?flowTgtRef ;
        bboExt:messageRef ?messageId .

  FILTER(
    STRENDS(STR(?node), ?flowSrcRef) || STRENDS(STR(?node), ?flowTgtRef)
  )

  OPTIONAL {
    ?message a bboExt:Message ;
              tai:belongsTo ?choreo ;
              bboExt:messageRef ?messageId .
  }

  OPTIONAL {
    ?message2 a bboExt:Message ;
               tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?message2), ?messageId))
    OPTIONAL { ?message2 bbo:name ?messageName . }
    BIND(?messageId AS ?messageId2)
  }

  BIND(COALESCE(?messageName, STR(?messageId)) AS ?messageName)
}
LIMIT 25

