  ?choreo tai:belongsTo ?definitions .

  ?node a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?nodeName .
  FILTER(LCASE(STR(?nodeName)) = LCASE("Get client to add the relevant cost centre"))

  BIND(REPLACE(STR(?node), "^.*?/", "") AS ?nodeIdLocal)

  ?flow a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:sourceRef ?flowSrcRef ;
        bboExt:targetRef ?flowTgtRef ;
        bboExt:messageRef ?messageId .

  FILTER(
    LCASE(?flowSrcRef) = LCASE(?nodeIdLocal) ||
    LCASE(?flowTgtRef) = LCASE(?nodeIdLocal)
  )

  OPTIONAL {
    ?message a bboExt:Message ;
              tai:belongsTo ?choreo ;
              bboExt:messageRef ?messageId ;
              bbo:name ?messageName .
